--Originally built to use SADATE, when rebuilding it using Keydate it was quicker to use the below alias than it would have been to rebuild the pivot tables SELECT Analysis.SAREF, ORDERH.UF_KEYDATE as [SADATE], Analysis.SAINV, Analysis.SACUST, Analysis.SAINCOTERMS, Sum(Analysis.SAORGQTY), ORDERH.SEQTYPE, ORDERH.CONSEDI , ORDERH.UF_CSA, Orderh.Conscode, Left(Analysis.SAProduct,1) as [ProductRange], ORDERH.cons1, ORDERH.cons2, ORDERH.cons3, ORDERH.cons4, ORDERH.cons5 FROM NISAINT_CS\Analysis Analysis, NISAINT_CS\ORDERH ORDERH WHERE Analysis.SAREF = ORDERH.REF AND ((ORDERH.UF_KEYDATE>={d '2022-04-02'}) AND (ORDERH.UF_KEYDATE<={d '2023-04-01'}) AND ((Analysis.SAPRODUCT Like '1%') OR (Analysis.SAPRODUCT Like '2%') OR (Analysis.SAPRODUCT Like '3%'))) AND Analysis.SAINV is not NULL GROUP BY Analysis.SAREF, ORDERH.SEQTYPE, ORDERH.CONSEDI, [ProductRange] UNION SELECT Analysis.SAREF, ORDERH.OHSPLPRICEPOINT as [SADATE], Analysis.SAINV, Analysis.SACUST, Analysis.SAINCOTERMS, Sum(Analysis.SAORGQTY), ORDERH.SEQTYPE, ORDERH.CONSEDI , ORDERH.UF_CSA, Orderh.Conscode, Left(Analysis.SAProduct,1) as [ProductRange], ORDERH.cons1, ORDERH.cons2, ORDERH.cons3, ORDERH.cons4, ORDERH.cons5 FROM NISAINT_CS\Analysis Analysis, NISAINT_CS\ORDERH ORDERH WHERE Analysis.SAREF = ORDERH.REF AND ((ORDERH.OHSPLPRICEPOINT>={d '2022-04-02'}) AND (ORDERH.OHSPLPRICEPOINT<={d '2023-04-01'}) AND ((Analysis.SAPRODUCT Like '1%') OR (Analysis.SAPRODUCT Like '2%') OR (Analysis.SAPRODUCT Like '3%'))) AND Analysis.SAINV is not NULL AND ORDERH.UF_KEYDATE is NULL GROUP BY Analysis.SAREF, ORDERH.SEQTYPE, ORDERH.CONSEDI, [ProductRange]
